import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { ReactNode } from 'react';
import React from 'react';

import { Icon } from '../Icon';
import { Typography } from '../Typography';

export const renderChildren = (
	children: ReactNode | ReactNode[],
	isCollapsed: boolean,
	onClick: () => void,
): React.JSX.Element[] => {
	const childrenLength = (children as React.ReactNode[])?.length;
	const separator = <Icon iconName={Icons.NavArrowRight} className="dsb-breadcrumbs__separator-icon" size="small" />;

	if (!isCollapsed || childrenLength < 3 || !childrenLength) {
		return (Array.isArray(children) ? children : ([children] as React.ReactNode[]))?.reduce(
			(res: React.JSX.Element[], link: React.ReactNode, i: number) => {
				res.push(
					<li className="dsb-breadcrumbs__item" key={i} itemProp="itemListElement">
						{link}
						<meta itemProp="position" content={String(i + 1)} />
					</li>,
				);

				if (i < childrenLength - 1) {
					res.push(
						<li className="dsb-breadcrumbs__separator" key={`${i}${separator}`}>
							{separator}
						</li>,
					);
				}

				return res;
			},
			[],
		);
	}
	return [
		<li className="dsb-breadcrumbs__item" key={'a'} itemProp="itemListElement">
			{children?.[0]}
			<meta itemProp="position" content={'1'} />
		</li>,
		<li className="dsb-breadcrumbs__separator" key={'b'}>
			{separator}
		</li>,
		<Typography className="dsb-breadcrumbs__dots" variant={'body3'} key={'c'} onClick={onClick}>
			...
		</Typography>,
		<li className="dsb-breadcrumbs__separator" key={'d'}>
			{separator}
		</li>,
		<li className="dsb-breadcrumbs__item" key={'e'}>
			{children?.[childrenLength - 1]}
			<meta itemProp="position" content={String(childrenLength)} />
		</li>,
	];
};
